import React, { useState } from 'react';
import { 
    Typography, 
    Button, 
    Grid, 
    Card, 
    CardContent, 
    CardActionArea, 
    CardMedia, 
    CardActions 
} from '@mui/material';
import EntranceAnimation from './EntranceAnimation';
import { useNavigate } from 'react-router-dom';

const Home = () => {
  const [animationCompleted, setAnimationCompleted] = useState(false);

  const handleAnimationEnd = () => {
      setAnimationCompleted(true);
  };

  const navigate = useNavigate();

  const handleButtonClick = () => {
    navigate('/about');
  };

  return (
    <div>
      {!animationCompleted && (
        <EntranceAnimation onAnimationEnd={handleAnimationEnd} />
      )}
      {animationCompleted && (
        <>
          {/* Hero Section */}
          <section style={{ textAlign: 'center', padding: '50px 0' }}>
              <Typography variant="h2" gutterBottom>
                  Welcome to Our Platform!
              </Typography>
              <Typography variant="h6" paragraph>
                  Discover our awesome services and products.
              </Typography>
              <Button variant="contained" color="primary">
                  Learn More
              </Button>
          </section>

          {/* Features Section */}
          <section style={{ padding: '50px 0' }}>
              <Typography variant="h4" gutterBottom>
                  Features
              </Typography>
              <Grid container spacing={4}>
                  {/* Feature 1 */}
                  <Grid item xs={12} sm={4}>
                      <Card>
                          <CardContent>
                              <Typography variant="h6">Feature 1</Typography>
                              <Typography>Description of the first feature.</Typography>
                          </CardContent>
                      </Card>
                  </Grid>
                  {/* Feature 2 */}
                  <Grid item xs={12} sm={4}>
                      <Card>
                          <CardContent>
                              <Typography variant="h6">Feature 2</Typography>
                              <Typography>Description of the second feature.</Typography>
                          </CardContent>
                      </Card>
                  </Grid>
                  {/* Feature 3 */}
                  <Grid item xs={12} sm={4}>
                      <Card>
                          <CardContent>
                              <Typography variant="h6">Feature 3</Typography>
                              <Typography>Description of the third feature.</Typography>
                          </CardContent>
                      </Card>
                  </Grid>
              </Grid>
          </section>

          {/* Latest News/Blogs Preview */}
          <section style={{ padding: '50px 0' }}>
            <Typography variant="h4" gutterBottom>
              Latest News
            </Typography>
            <Grid container spacing={4}>
              <Grid item xs={12} sm={4}>
                <Card>
                  <CardActionArea>
                    <CardMedia
                      component="img"
                      alt="News Image"
                      height="140"
                      image="/path/to/image.jpg"
                    />
                    <CardContent>
                      <Typography variant="h6">Article Title</Typography>
                      <Typography>Short description or excerpt from the article...</Typography>
                    </CardContent>
                  </CardActionArea>
                  <CardActions>
                    <Button size="small" color="primary">
                      Read More
                    </Button>
                  </CardActions>
                </Card>
              </Grid>
              {/* Repeat for more articles */}
            </Grid>
          </section>

          {/* Testimonials */}
          <section style={{ textAlign: 'center', padding: '50px 0' }}>
            <Typography variant="h4" gutterBottom>
              What Our Customers Say
            </Typography>
            <Typography variant="body1" style={{ fontStyle: 'italic' }}>
              "This is a great service! Highly recommended." - Customer Name
            </Typography>
            <Typography variant="body1" style={{ fontStyle: 'italic', marginTop: '20px' }}>
              "Amazing experience. Will come back again." - Another Customer
            </Typography>
          </section>

          {/* Final Call-to-Action */}
          <section style={{ textAlign: 'center', padding: '50px 0' }}>
            <Typography variant="h4" gutterBottom>
              Explore Our Offerings!
            </Typography>
            <Typography variant="h6" paragraph>
              Dive in and discover what makes us special.
            </Typography>
            <Button 
              variant="contained" 
              color="primary" 
              onClick={handleButtonClick}
            >
              Learn More
            </Button>
          </section>
        </>
      )}
    </div>
  );
};

export default Home;
