import React, { useState } from 'react';
import { 
    List, 
    TextField, 
    InputAdornment, 
    IconButton, 
    Grid, 
    Typography 
} from '@mui/material';
import SearchIcon from '@mui/icons-material/Search';
import ArrowLeftTwoToneIcon from '@mui/icons-material/ArrowLeftTwoTone';
import ArrowRightTwoToneIcon from '@mui/icons-material/ArrowRightTwoTone';

import { 
    AnimeTitle, 
    YearButtonsContainer, 
    YearButton, 
    AnimeSeason, 
    AnimeListItem, 
    AnimeLink 
} from './Styles';
import { animeList } from './AnimeList.js';

function Fun() {
  const currentYear = new Date().getFullYear();
  const years = Object.keys(animeList);
  const initialSelectedYearIndex = years.indexOf(currentYear.toString());
  const [selectedYearIndex, setSelectedYearIndex] = useState(initialSelectedYearIndex);
  const [searchTerm, setSearchTerm] = useState('');

  const handleYearChange = (increment) => {
    const newIndex = selectedYearIndex + increment;
    if (newIndex >= 0 && newIndex < years.length) {
      setSelectedYearIndex(newIndex);
    }
  };

  const selectedYear = years[selectedYearIndex];
  const allAnime = Object.values(animeList[selectedYear] || {}).reduce((acc, curr) => acc.concat(curr), []);
  const filteredAnime = allAnime.filter(anime => 
    anime.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div>
      <AnimeTitle>Anime List</AnimeTitle>
      
      <TextField
        fullWidth
        type="text"
        variant="outlined"
        placeholder="Search for anime..."
        value={searchTerm}
        onChange={e => setSearchTerm(e.target.value)}
        InputProps={{
          startAdornment: (
            <InputAdornment position="start">
              <Grid container alignItems="center">
                <Grid item>
                  <IconButton>
                    <SearchIcon />
                  </IconButton>
                </Grid>
              </Grid>
            </InputAdornment>
          ),
        }}
      />

      {searchTerm ? (
        <List>
          {filteredAnime.map(anime => (
            <AnimeListItem key={anime.name}>
              <AnimeLink href={anime.url} title={anime.title}>
                {anime.name}
              </AnimeLink>
            </AnimeListItem>
          ))}
        </List>
      ) : (
        <div>
          <YearButtonsContainer>
            <YearButton variant="outlined" onClick={() => handleYearChange(-1)}>
              <ArrowLeftTwoToneIcon fontSize="large" />
            </YearButton>

            <Typography>
              <AnimeSeason>{selectedYear}</AnimeSeason>
            </Typography>

            <YearButton variant="outlined" onClick={() => handleYearChange(1)}>
              <ArrowRightTwoToneIcon fontSize="large" />
            </YearButton>
          </YearButtonsContainer>

          {['Fall', 'Summer', 'Spring', 'Winter'].map(season => (
            <div key={season} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
              {animeList[selectedYear] && animeList[selectedYear][season] && animeList[selectedYear][season].length > 0 && (
                <div>
                  <Typography style={{ textAlign: 'center'}}>
                    <AnimeSeason>{season}</AnimeSeason>
                  </Typography>

                  <List>
                    {animeList[selectedYear][season].map(anime => (
                      <AnimeListItem key={anime.name}>
                        <AnimeLink>
                          <a href={anime.url} title={anime.title} target="_blank" rel="noopener noreferrer">
                            <Typography style={{ textAlign: 'center' }}>
                              {anime.name}
                            </Typography>
                          </a>
                        </AnimeLink>
                      </AnimeListItem>
                    ))}
                  </List>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default Fun;
